    taskType: 'interview_chat',
    routeId: 'anthropic_claude_haiku_4_5_interview_primary', // primary → throws → fallback to openai_gpt4o_interview_fallback
    promptVersion: 'r2-smoke',
    blocks: baseBlocks,
