        </div>
      )}
      {refreshUnenrichedCount > 0 && (
        <p className="text-xs text-muted-foreground">
          {refreshUnenrichedCount} model{refreshUnenrichedCount === 1 ? '' : 's'} without OpenRouter enrichment data — hidden from the table.
        </p>
      )}

      {/* Pool counts + reset */}
