    : [];
  const domainHints = Array.isArray(proposal.proposed_domain_hints)
    ? (proposal.proposed_domain_hints as string[])
    : [];

  const onApprove = () => {
    if (!finalValue.trim()) {
      setError('Canonical value cannot be empty.');
      return;
    }
    setError(null);
    startTransition(async () => {
      try {
        await approveEntityProposal(
